public class task_2 {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		 int temperature = 25;
		 
		 if(temperature < 20) {
			 System.out.println("Cold");
		 }else if(temperature>=20 && temperature <= 30) {
			 System.out.println("Warm");
		 }else if(temperature > 30) {
			 System.out.println("Hot");
		 }
	}

}
